use std::vec::Vec;
use std::hint::black_box;

extern "Rust" {
    fn do_reserve_and_handle(this_: &mut Vec<u8>, used: usize, additional: usize, align: u64, alloc: u64) -> i64;
}

fn vec_reserve(this_: &mut Vec<u8>, additional: usize) {
    let len: usize = black_box(0);
    let rax: usize = black_box(0);
    let spare_capacity = rax.wrapping_sub(len);
    if spare_capacity < additional {
        unsafe { do_reserve_and_handle(this_, len, additional, 1, 1); }
    }
}

