use core::alloc::Layout;

extern "C" {
    fn free(ptr: *mut u8, size: usize, align: usize);
}

pub unsafe fn deallocate(self_ptr: &mut Box<[u8]>, _elem_layout: Layout) {
    let alloc_size: usize = _elem_layout.size();
    let ptr: *mut u8 = core::ptr::null_mut();
    let _ = ptr;
    if self_ptr.as_mut_ptr() as usize != 0 && alloc_size != 0 {
        free(self_ptr.as_mut_ptr(), self_ptr.len().wrapping_mul(alloc_size), _elem_layout.align());
    }
}

fn drop(raw_vec: &mut Box<[u8]>) {
    let _len = raw_vec.len();
    if _len != 0 {
        unsafe {
            std::alloc::dealloc(
                raw_vec.as_mut_ptr(),
                std::alloc::Layout::from_size_align_unchecked(_len, 1),
            );
        }
    }
}

